import java.util.ArrayList;
import java.util.List;

public class ParenthesisSeparator {

    public static List<String> separateParenGroups(String parenString) {
        // Remove spaces from the input string
        parenString = parenString.replace(" ", "");

        List<String> groups = new ArrayList<>();
        StringBuilder currentGroup = new StringBuilder();
        int balance = 0;

        for (char ch : parenString.toCharArray()) {
            if (ch == '(') {
                balance++;
                currentGroup.append(ch);
            } else if (ch == ')') {
                balance--;
                currentGroup.append(ch);
            }

            // When balance is zero, we have a complete group
            if (balance == 0 && currentGroup.length() > 0) {
                groups.add(currentGroup.toString());
                currentGroup.setLength(0); // Reset for the next group
            }
        }

        return groups;
    }
}
